#include<bits/stdc++.h>
using namespace std;
struct edge
{
    long long to,val,nxt,cost;
}e[200010];
long long head[200010],tot=1,res;
long long n,m,s,t,d[200010],now[200010];
bool vis[200010];
void add1(long long u,long long v,long long w,long long c)
{
    e[++tot]=(edge){v,w,head[u],c};
    head[u]=tot;
}
void add(long long u,long long v,long long w,long long c)
{
    add1(u,v,w,-c);
    add1(v,u,0,c);
}
bool spfa()
{
    memset(d,0x3f,sizeof(d));
    long long tmp=d[0];
    queue<long long> q;
    q.push(s);
    d[s]=0;
    while(!q.empty())
    {
        int t=q.front();
        q.pop();
        vis[t]=false;
        for(int i=head[t];i;i=e[i].nxt)
        {
            int v=e[i].to,cost=e[i].cost;
            if(e[i].val&&d[v]>d[t]+cost)
            {
                d[v]=d[t]+cost;
                if(!vis[v])
                {
                    vis[v]=true;
                    q.push(v);
                }
            }
        }
    }
    return d[t]<tmp;
}
long long dfs(long long x,long long flow)
{
    if(x==t)
    {
        return flow;
    }
    vis[x]=true;
    long long sum=0;
    for(long long i=now[x];i;i=e[i].nxt)
    {
        now[x]=i;
        long long v=e[i].to,val=e[i].val,cost=e[i].cost;
        if(!vis[v]&&d[v]==d[x]+cost&&val)
        {
            long long tmp=dfs(v,min(flow,val));
            e[i].val-=tmp;
            e[i^1].val+=tmp;
            sum+=tmp;
            res+=tmp*cost;
            flow-=tmp;
        }
    }
    vis[x]=false;
    return sum;
}
long long dinic()
{
    long long ans=0;
    while(spfa())
    {
        for(long long i=0;i<=t;i++)
        {
            now[i]=head[i];
        }
        ans+=dfs(s,INT_MAX);
    }
    return ans;
}
string name[100010];
map<string,int> mp;
void dfs1(int x)
{
    cout<<name[x]<<"\n";
    vis[x]=true;
    for(int i=head[x];i;i=e[i].nxt)
    {
        int v=e[i].to;
        if(v>n&&v<=n*2&&e[i].val==0)
        {
            dfs1(v-n);
            break;
        }
    }
}
void dfs2(int x)
{
    vis[x]=true;
    for(int i=head[x];i;i=e[i].nxt)
    {
        int v=e[i].to;
        if(v>n&&v<=n*2&&e[i].val==0&&!vis[v-n])
        {
            dfs2(v-n);
            break;
        }
    }
    cout<<name[x]<<"\n";
}
int main()
{
    scanf("%lld%lld",&n,&m);
    s=0;
    t=n*2+1;
    bool flag=false;
    for(int i=1;i<=n;i++)
    {
        cin>>name[i];
        mp[name[i]]=i;
    }
    for(int i=1;i<=m;i++)
    {
        string s1,s2;
        cin>>s1>>s2;
        int x=mp[s1],y=mp[s2];
        if(x>y)
        {
            swap(x,y);
        }
        if(x==1&&y==n)
        {
            flag=true;
        }
        add(x,y+n,1,0);
    }
    add(s,n+1,2e9,0);
    add(n,t,2e9,0);
    for(int i=1;i<=n;i++)
    {
        if(i!=1&&i!=n)
        {
            add(i+n,i,1,1);
        }
        else
        {
            add(i+n,i,2,1);
        }
    }
    long long ans=dinic();
    if(ans==2)
    {
        printf("%lld\n",(-res)-2);
    }
    else if(ans==1&&flag)
    {
        printf("2\n");
        cout<<name[1]<<"\n"<<name[n]<<"\n"<<name[1];
        return 0;
    }
    else
    {
        printf("No Solution!");
        return 0;
    }
    memset(vis,0,sizeof(vis));
    dfs1(1);
    dfs2(1);
    return 0;
}
